TITLE I-h channel from Magee 1998 for distal dendrites

UNITS {
	(mA) = (milliamp)
	(mV) = (millivolt)

}

PARAMETER {
	v 		(mV)
        ehd  		(mV)        
	celsius 	(degC)
	ghdbar=.0001 	(mho/cm2)
        vhalfl=-100   	(mV)
	kl=-12
        vhalft=-75   	(mV)
        a0ta=0.001      	(/ms)
        a0td=0.009      	(/ms)
        zetat=2.2    	(1)
        gmt=.4   	(1)
	q10=4.5
	qtl=1
}


NEURON {
	SUFFIX hd
	NONSPECIFIC_CURRENT i
        RANGE ghdbar, vhalfl, tau
        GLOBAL linf,taua, taud
}

STATE {
        l
}

ASSIGNED {
	i (mA/cm2)
        linf      
	tau
        taua
        taud
        ghd
}

INITIAL {
	rate(v)
	l=linf
}


BREAKPOINT {
	SOLVE states METHOD cnexp
	ghd = ghdbar*l
	i = ghd*(v-ehd)

}


FUNCTION alpt(v(mV)) {
  alpt = exp(0.0378*zetat*(v-vhalft)) 
}

FUNCTION bett(v(mV)) {
  bett = exp(0.0378*zetat*gmt*(v-vhalft)) 
}

DERIVATIVE states {     : exact when v held constant; integrates over dt step
        rate(v)
        if (l<linf) {tau=taua} else {tau=taud}
        l' =  (linf - l)/tau
}

PROCEDURE rate(v (mV)) { :callable from hoc
        LOCAL a,qt
        qt=q10^((celsius-33)/10)
        a = alpt(v)
        linf = 1/(1 + exp(-(v-vhalfl)/kl))
        taua = bett(v)/(qtl*qt*a0ta*(1+a))
        taud = bett(v)/(qtl*qt*a0td*(1+a))
}

COMMENT
a synaptic current with NMDA function conductance defined by
        i = g * (v - e)      i(nanoamps), g(micromhos);
        where
         g = 0 for t < onset and
         g = gmax * (exp(-(t - onset)/tau1)- exp(-(t - onset )/tau2))
                  / (1+etha*[Mg2+]*exp(-gamma*v))
          for t > onset
this has the property that the maximum value is gmax and occurs at
 t = delay + tau.
written by D.Rusakov, 1995
ENDCOMMENT

INDEPENDENT {t FROM 0 TO 1 WITH 1 (ms)}

NEURON {
	POINT_PROCESS NMDAsyn
	RANGE onset, tau1, tau2, Mgetha, gamma, gmax, e, i
	NONSPECIFIC_CURRENT i
}
UNITS {
	(molar) = (1/liter)
	(mM)	= (millimolar)
	(nA) = (nanoamp)
	(mV) = (millivolt)
	(umho) = (micromho)
}

PARAMETER {
	onset=0 (ms)
	tau1=80 (ms)
	tau2=0.67 (ms)
	Mgetha=0.33
	gamma=0.06 (/mV)
	gmax=0 	(umho)
	e=0	(mV)
	v	(mV)
}

ASSIGNED { i (nA)  g (umho)}

BREAKPOINT {
	g = gmax*alpha( (t - onset)/tau1, (t - onset)/tau2)
	i = g*(v - e) / (1.+Mgetha*exp(-1.*gamma*v)) 
}

FUNCTION alpha(x1,x2) {
	if (x1 < 0 || x1> 10) { if (x2 < 0 || x2> 200) {
		alpha = 0
	}}else{
		alpha = exp(-x1)-exp(-x2)
	}
}

TITLE Purkinje simplified Cell model

COMMENT
        kM channel
        
        Authors: Niceto R. Luque & Richard R. Carrillo
		Last revised: 13.9.2018
		Paper related:Burst-pause Purkinje dynamics regulate motor adaptation
   
ENDCOMMENT
 
NEURON { 
	SUFFIX Purk_gKM
	USEION k READ ek WRITE ik
	RANGE gkmbar, ik, g


	RANGE M_inf, tau_M, M
} 
 
UNITS { 
	(mA) = (milliamp) 
	(mV) = (millivolt) 
	(molar) = (1/liter)
	(mM) = (millimolar)
} 
 
PARAMETER { 

	v (mV) 
	gkmbar= 0.001 (mho/cm2)
	ek = 125 (mV)
} 

STATE { 
	M
} 

ASSIGNED { 
	ik (mA/cm2) 

	M_inf 
	tau_M (ms) 
	g (mho/cm2)
	alpha_M (/ms) 
	beta_M (/ms)
} 
 
INITIAL { 
	rate(v) 
	M = M_inf 
} 
 
BREAKPOINT { 
	SOLVE states METHOD derivimplicit 
	g = gkmbar*M
	ik = g*(v - ek)
	alpha_M = alp_M(v) 
	beta_M = bet_M(v)
} 
 
DERIVATIVE states { 
	rate(v) 
	M' =(M_inf - M)/tau_M
} 
 
FUNCTION alp_M(v(mV))(/ms) {
	alp_M = 0.02/(1 + exp((-v - 20)/5))
} 
 
FUNCTION bet_M(v(mV))(/ms) {
	bet_M = 0.01*exp((-v - 43)/18)
} 

PROCEDURE rate(v (mV)) { LOCAL a_M, b_M
	a_M = alp_M(v)  
	b_M = bet_M(v) 
	tau_M = 1/(a_M + b_M)
	M_inf = a_M/(a_M + b_M) 
}

COMMENT
Four helpful hints:

1) before calling scale_connection_coef, one must call some NEURON
function (such as ri(x)) that forces calculation of all the connection
coefficients for all the sections.

2) if any diam or L is changed, then one must re-call the
scale_connection_coef procedure again for all compartments AFTER
re-forcing the normal calculation of them via a call to, e.g. ri(x).

3) note that ri(0.5) gives the resistance in mega ohms between 0.5
location and the 0 end and ri(1) gives the resistance in mega ohms
between the 0.5 location and the 1 end.

4) Call with a section access'ed.  Call below with (1,factor) to
change the axial resistance of (a parent's) x=0.5 to x=1 part and call
with (0.5, factor) to change the axial resistance for (a child's) x=0
to x=0.5 part.  Note: factor = current_ri_value/desired__ri_value.

ENDCOMMENT

NEURON { SUFFIX nothing }

VERBATIM
const char* secname();
ENDVERBATIM

VERBATIM
#ifndef _NrnThread
#define _NrnThread NrnThread
#endif
#ifdef NRN_MECHANISM_DATA_IS_SOA
#define get_nnode(sec) _nrn_mechanism_get_nnode(sec)
#define get_node(sec, node_index) _nrn_mechanism_get_node(sec, node_index)
#define get_thread(node) _nrn_mechanism_get_thread(node)
#else
#define get_nnode(sec) sec->nnode
#define get_node(sec, node_index) sec->pnode[node_index]
#define get_thread(node) node->_nt
#endif
ENDVERBATIM

PROCEDURE scale_connection_coef(x, factor) {
VERBATIM {
	Section* sec;
	Node* nd;
#if defined(t)
	_NrnThread* _nt = nrn_threads;
#endif /* t */
	sec = chk_access();
	if (_lx <= 0. || _lx > 1.) {
		hoc_execerror("out of range, must be 0 < x <= 1", (char*)0);
	}
	/*printf("scale_connection_coefs %s(%g) %d\n", secname(sec), _lx, get_nnode(sec));*/
	/* assumes 0 end of child connected to parent */
	if (_lx == 1.) {
		nd = get_node(sec, get_nnode(sec) - 1);
	}else{
		nd = get_node(sec, (int)(_lx*(double)(get_nnode(sec) - 1)));
	}
#if defined(t)        
	_nt = get_thread(nd);
#endif /* t */
	/*printf("%g %g\n", NODEA(nd), NODEB(nd));*/
	NODEA(nd) *= _lfactor;
	NODEB(nd) *= _lfactor;
}
ENDVERBATIM
}

TITLE Potasium dr type current for RD Traub, J Neurophysiol 89:909-921, 2003

COMMENT
       Implemented by Aniruddha Yadav 2007 (aniruddha.yadav@mssm.edu)

ENDCOMMENT

UNITS {
        (mV) = (millivolt)
}

NEURON {
         SUFFIX kdr
         RANGE gbar
         USEION k READ ek WRITE ik
         RANGE Vkd, ik, vrev
         RANGE a1, a2, b1, b2
}

PARAMETER {
           gbar=0.0    (mho/cm2)
           Vkd = 10.0  (mV)
           a1 =0.25    (ms)
           b1 = 4.35   (ms)
           a2 = 0.25   (ms)
           b2=  4.35   (ms)
           ek        (mV)
           vrev = 29.5 (mV)
}

ASSIGNED {
           ik     (mA/cm2)
           minf   (1)
           mtau   (ms)
           v      (mV)
}

STATE {
     m
}

INITIAL {
         rates(v)
         m=minf
}

BREAKPOINT {
             SOLVE states METHOD cnexp
             ik = gbar * m * m * m * m * (v - ek )
}

INITIAL {
          rates(v)
          m = minf
}

DERIVATIVE states {
        rates(v)
        m' = (minf - m ) / mtau
}

UNITSOFF

PROCEDURE rates(V (mV)) {

        minf  = 1 / ( 1 + exp( ( -V - vrev) / 10 ) )
        if( V < -Vkd ) {
                mtau = a1 + b1 * exp( ( V + Vkd ) / 10 )
        }else{
                mtau = a2 + b2 * exp( ( -V - Vkd ) / 10 )
        }
}

UNITSON

NEURON {
   POINT_PROCESS Gap
   POINTER vgap
   RANGE r, i   
   NONSPECIFIC_CURRENT i
}

PARAMETER { r = 1e10 (megohm) }

ASSIGNED {
   v (millivolt)
   vgap (millivolt)
   i (nanoamp)
}

BREAKPOINT { i = (v - vgap)/r }

